mapper.select:
select data_info dataInfo from DGN_DATA_LARGE_SCREEN


		and module_id=#{moduleId}


		and to_char(create_time, 'yyyyMMdd')=#{createTime}

mapper.delete:
delete from DGN_DATA_LARGE_SCREEN


		and module_id = #{moduleId}


		and to_char(create_time, 'yyyyMMdd') < #{createTime}

mapper.select:
select v.CODEID dataId, v.CODETEXT dataName, nvl(TRUNC(tableAllSum/100000000,2),0) dataCount, nvl(t.tableNumberSum,0) typeCount, nvl(TRUNC(yesterdayAllSum/100000000,2),0) todayUpdateCount from v_classify_info v left join ( select PRIMARY_ORGANIZATION_CH as primaryClassifyCh , SECONDARY_ORGANIZATION_CH as secondaryClassifyCh, sum(table_all_count) as tableAllSum , count(distinct table_name_en) as tableNumberSum, sum(YESTERDAY_COUNT) as yesterdayAllSum from (SELECT PRIMARY_ORGANIZATION_CH,SECONDARY_ORGANIZATION_CH,table_all_count,table_name_en,YESTERDAY_COUNT FROM ( SELECT j.PRIMARY_ORGANIZATION_CH,j.SECONDARY_ORGANIZATION_CH,j.table_all_count,j.table_name_en,j.YESTERDAY_COUNT, row_number() over ( PARTITION BY lower(TABLE_PROJECT), upper(TABLE_NAME_EN) ORDER BY STATISTICS_TIME DESC ) as rnn from DP_TABLE_ORGANIZATION_ASSETS j where j.STATISTICS_TIME >= trunc(sysdate)) h WHERE h.rnn = 1) group by PRIMARY_ORGANIZATION_CH,SECONDARY_ORGANIZATION_CH ) t on t.secondaryClassifyCh = v.CODETEXT where level = 3
and parcodeid = #{dataId}
start with codeid = #{sjzzflCodeId} connect by prior codeid = parcodeid

select v.CODEID dataId, v.CODETEXT dataName, nvl(t.tableNumberSum,0) typeCount from v_classify_info v left join ( select PRIMARY_DATASOURCE_CH as primaryClassifyCh , SECONDARY_DATASOURCE_CH as secondaryClassifyCh, count(distinct table_name_en) as tableNumberSum from (SELECT PRIMARY_DATASOURCE_CH,SECONDARY_DATASOURCE_CH,table_name_en FROM ( SELECT j.PRIMARY_DATASOURCE_CH,j.SECONDARY_DATASOURCE_CH,j.table_name_en, row_number() over ( PARTITION BY lower(TABLE_PROJECT), upper(TABLE_NAME_EN) ORDER BY STATISTICS_TIME DESC ) as rnn from DP_TABLE_ORGANIZATION_ASSETS j where j.STATISTICS_TIME >= trunc(sysdate)) h WHERE h.rnn = 1) group by PRIMARY_DATASOURCE_CH,SECONDARY_DATASOURCE_CH ) t on t.secondaryClassifyCh = v.CODETEXT where level = 4
and parcodeid = #{dataId}
start with codeid = #{sjzzflCodeId} connect by prior codeid = parcodeid

        select resource_id sourceId, data_count dataCount, service_ip nodeInstanceId, to_char(data_arrive_time,'yyyy-MM-dd') dataTime
		from DAC_STANDARD_ACCEPTOR_BILL
		where data_arrive_time between #{startTime} and #{endTime}
